w("p6_29_coordinate_shapes.py", T("P6_CoordinateShapes","P6","Shapes on Coordinates","Plot and find", prob("Rectangle: (1,1),(5,1),(5,3),(1,3). Area?") + "        axes=Axes(x_range=[0,6,1],y_range=[0,4,1],x_length=6,y_length=4,axis_config={'color':WHITE_C,'font_size':14}).move_to(DOWN*0.2)\n        self.play(Create(axes),run_time=0.4)\n        pts=[(1,1),(5,1),(5,3),(1,3)]\n        dots=VGroup(*[Dot(axes.c2p(x,y),radius=0.08,color=GOLD) for x,y in pts])\n        rect=Polygon(*[axes.c2p(x,y) for x,y in pts],color=TEAL,fill_opacity=0.2,stroke_width=2)\n        self.play(Create(rect),LaggedStart(*[GrowFromCenter(d) for d in dots],lag_ratio=0.1),run_time=0.6)\n" + ans("Area = 4 x 2 = 8 sq units")))
w("p6_30_transformation_reflect.py", T("P6_TransformReflect","P6","Reflection","Mirror image", prob("Reflect triangle in y-axis") + "        axes=Axes(x_range=[-4,4,1],y_range=[-1,4,1],x_length=8,y_length=5,axis_config={'color':WHITE_C,'font_size':14}).move_to(DOWN*0.2)\n        self.play(Create(axes),run_time=0.4)\n        tri=Polygon(axes.c2p(1,1),axes.c2p(3,1),axes.c2p(2,3),color=TEAL,fill_opacity=0.3,stroke_width=2)\n        ref=Polygon(axes.c2p(-1,1),axes.c2p(-3,1),axes.c2p(-2,3),color=ACCENT,fill_opacity=0.3,stroke_width=2)\n        self.play(Create(tri),run_time=0.4)\n        self.play(Create(ref),run_time=0.4)\n" + ans("Reflected across y-axis!")))


w("p6_31_transformation_rotate.py", T("P6_TransformRotate","P6","Rotation","Turn shapes", prob("Rotate square 90 degrees") + "        sq=Square(side_length=1.5,color=TEAL,fill_opacity=0.3).move_to(LEFT*2+UP*0.3)\n        dot=Dot(sq.get_corner(UR),radius=0.1,color=GOLD)\n        self.play(Create(sq),GrowFromCenter(dot),run_time=0.4)\n        sq2=sq.copy().set_color(ACCENT)\n        dot2=dot.copy()\n        self.play(Rotate(VGroup(sq2,dot2),PI/2,about_point=ORIGIN),run_time=0.8)\n        self.play(FadeIn(sq2),run_time=0.3)\n" + ans("Rotated 90 degrees!")))
w("p6_32_transformation_translate.py", T("P6_TransformTranslate","P6","Translation","Slide shapes", prob("Translate triangle 3 right, 2 up") + "        axes=Axes(x_range=[-1,6,1],y_range=[-1,5,1],x_length=7,y_length=6,axis_config={'color':WHITE_C,'font_size':14}).move_to(DOWN*0.2)\n        self.play(Create(axes),run_time=0.4)\n        tri=Polygon(axes.c2p(0,0),axes.c2p(2,0),axes.c2p(1,2),color=TEAL,fill_opacity=0.3,stroke_width=2)\n        self.play(Create(tri),run_time=0.4)\n        tri2=tri.copy().set_color(GOLD)\n        self.play(tri2.animate.shift(axes.c2p(3,2)-axes.c2p(0,0)),run_time=0.8)\n" + ans("Translated (3,2)!")))
w("p6_33_pct_profit.py", T("P6_PctProfit","P6","Profit Percentage","Business math", prob("Cost $200, sell $250. Profit %?") + steps(["Profit = 250-200 = $50","Profit % = 50/200 x 100","= 25%"]) + ans("Profit = 25%")))
w("p6_34_pct_loss.py", T("P6_PctLoss","P6","Loss Percentage","Selling below cost", prob("Cost $80, sell $60. Loss %?") + steps(["Loss = 80-60 = $20","Loss % = 20/80 x 100","= 25%"]) + ans("Loss = 25%")))
w("p6_35_compound_interest.py", T("P6_CompoundInterest","P6","Compound Interest","Interest on interest", prob("$1000 at 10% for 2 years (compound)") + steps(["Year 1: 1000 x 1.10 = $1100","Year 2: 1100 x 1.10 = $1210","Interest = $210"]) + ans("After 2 years: $1210")))
w("p6_36_hire_purchase.py", T("P6_HirePurchase","P6","Hire Purchase","Installment buying", prob("TV $1200. Deposit 20%. 12 monthly $90.") + steps(["Deposit: 20% of 1200 = $240","Installments: 12 x $90 = $1080","Total: $240+$1080 = $1320","Extra: $1320-$1200 = $120"]) + ans("Extra paid = $120")))
w("p6_37_distance_time_graph.py", T("P6_DistTimeGraph","P6","Distance-Time Graph","Reading graphs", prob("Read the distance-time graph") + "        axes=Axes(x_range=[0,5,1],y_range=[0,100,20],x_length=6,y_length=3,axis_config={'color':WHITE_C,'font_size':14}).move_to(DOWN*0.3)\n        xl=Text('Time (h)',font_size=16,color=WHITE_C).next_to(axes,DOWN,buff=0.1)\n        yl=Text('Dist (km)',font_size=16,color=WHITE_C).next_to(axes,LEFT,buff=0.1)\n        self.play(Create(axes),Write(xl),Write(yl),run_time=0.5)\n        pts=[(0,0),(1,40),(2,40),(3,80),(4,80)]\n        for i in range(len(pts)-1):\n            l=Line(axes.c2p(*pts[i]),axes.c2p(*pts[i+1]),color=GOLD,stroke_width=2)\n            self.play(Create(l),run_time=0.3)\n" + ans("Flat line = stopped. Slope = speed")))
w("p6_38_speed_graph.py", T("P6_SpeedGraph","P6","Speed-Time Graph","Acceleration", prob("Speed increases from 0 to 60 in 3s") + "        axes=Axes(x_range=[0,5,1],y_range=[0,80,20],x_length=6,y_length=3,axis_config={'color':WHITE_C,'font_size':14}).move_to(DOWN*0.3)\n        self.play(Create(axes),run_time=0.4)\n        l1=Line(axes.c2p(0,0),axes.c2p(3,60),color=GOLD,stroke_width=2)\n        l2=Line(axes.c2p(3,60),axes.c2p(5,60),color=TEAL,stroke_width=2)\n        self.play(Create(l1),run_time=0.4)\n        self.play(Create(l2),run_time=0.3)\n" + ans("Slope = acceleration. Flat = constant")))
w("p6_39_sets_venn.py", T("P6_SetsVenn","P6","Venn Diagrams","Overlapping sets", prob("Math:20, Science:15, Both:8") + "        c1=Circle(radius=1.5,color=TEAL,fill_opacity=0.2).move_to(LEFT*0.8+UP*0.3)\n        c2=Circle(radius=1.5,color=ACCENT,fill_opacity=0.2).move_to(RIGHT*0.8+UP*0.3)\n        l1=Text('Math',font_size=20,color=TEAL).move_to(LEFT*2+UP*1.5)\n        l2=Text('Science',font_size=20,color=ACCENT).move_to(RIGHT*2+UP*1.5)\n        self.play(Create(c1),Create(c2),Write(l1),Write(l2),run_time=0.6)\n        self.play(Write(Text('12',font_size=22,color=TEAL).move_to(LEFT*1.5+UP*0.3)),run_time=0.2)\n        self.play(Write(Text('8',font_size=22,color=GOLD).move_to(UP*0.3)),run_time=0.2)\n        self.play(Write(Text('7',font_size=22,color=ACCENT).move_to(RIGHT*1.5+UP*0.3)),run_time=0.2)\n" + ans("Total = 12+8+7 = 27 students")))
w("p6_40_rate_word.py", T("P6_RateWord","P6","Rate Word Problem","Work rate", prob("Tap A fills in 6h, Tap B in 3h. Together?") + steps(["A rate: 1/6 per hour","B rate: 1/3 per hour","Together: 1/6+1/3 = 1/2","Time = 2 hours"]) + ans("Together: 2 hours")))
