w("p6_42_area_shaded.py", T("P6_AreaShaded","P6","Shaded Area","Subtract areas", prob("Square 10cm. Circle inside r=5. Shaded?") + steps(["Square area: 10x10=100","Circle area: 22/7 x 25 = 78.6","Shaded = 100-78.6 = 21.4"]) + ans("Shaded area = 21.4 sq cm")))
w("p6_43_ratio_3part.py", T("P6_Ratio3Part","P6","3-Part Ratio Problem","Three shares", prob("A:B:C = 2:3:5. Total=$200.") + steps(["Total parts: 2+3+5=10","1 part = $20","A=$40, B=$60, C=$100"]) + ans("A=$40, B=$60, C=$100")))
w("p6_44_algebra_fraction.py", T("P6_AlgebraFraction","P6","Algebra with Fractions","Fraction equations", prob("x/3 + 2 = 5") + steps(["x/3 = 5-2 = 3","x = 3 x 3 = 9","Check: 9/3+2 = 3+2 = 5 ✓"]) + ans("x = 9")))
w("p6_45_model_before_after.py", T("P6_ModelBeforeAfter","P6","Before-After Model","Change problems", prob("Ali had 3x Ben. Ali gave 20. Now equal.") + steps(["Before: Ali=3u, Ben=u","After: 3u-20 = u+20","2u = 40, u = 20","Ali had 60, Ben had 20"]) + ans("Ali=60, Ben=20")))
w("p6_46_challenging_pct.py", T("P6_ChallengingPct","P6","Challenging Percentage","Multi-step", prob("Price up 20%, then down 10%. Net change?") + steps(["Start: $100","Up 20%: $120","Down 10%: $108","Net: +8% (not +10%!)"]) + ans("Net change = +8%")))
w("p6_47_challenging_ratio.py", T("P6_ChallengingRatio","P6","Challenging Ratio","Complex sharing", prob("A:B=3:4, B:C=2:5. Find A:B:C.") + steps(["Make B same: A:B=3:4, B:C=2:5","B=4 and B=2, LCM=4","A:B=3:4, B:C=4:10","A:B:C = 3:4:10"]) + ans("A:B:C = 3:4:10")))
w("p6_48_psle_model.py", T("P6_PSLEModel","P6","PSLE Model Drawing","Exam technique", prob("Total 240. A is 2/5 of total. B is rest.") + steps(["A = 2/5 x 240 = 96","B = 240 - 96 = 144","Check: 96+144=240 ✓"]) + ans("A=96, B=144")))
w("p6_49_psle_speed.py", T("P6_PSLESpeed","P6","PSLE Speed Problem","Exam technique", prob("Car 80km/h, 2h. Bus 60km/h, same dist. Time?") + steps(["Distance = 80x2 = 160km","Bus time = 160/60","= 2h 40min"]) + ans("Bus takes 2h 40min")))
w("p6_50_review.py", T("P6_Review","P6","P6 Review Quiz","Test yourself!", prob("Final quiz!") + "        qs=[('3x+7=22, x=?','5'),('Avg speed 100km/3h=?','33.3'),('P(H and 6)=?','1/12')]\n        for i,(q,a) in enumerate(qs):\n            y=UP*0.5+DOWN*i*0.8\n            self.play(Write(Text(q,font_size=26,color=WHITE_C).move_to(LEFT*2+y)),run_time=0.3)\n            self.wait(0.3)\n            self.play(Write(Text(a,font_size=26,color=GOLD).move_to(RIGHT*2+y)),run_time=0.3)\n" + ans("Congratulations! Series complete!")))

